import React, { useState, useRef, useCallback, useEffect } from 'react';
import toast from 'react-hot-toast';
import {
  searchProducts, getProductByBarcode, createBill,
  getBills, getBill, editBillPayment, deleteBill
} from '../services/api';
import PrintBill from '../components/PrintBill';

const fmt = n => `₹${parseFloat(n || 0).toFixed(2)}`;

const payColor = {
  cash:     'badge-green',
  card:     'badge-blue',
  upi:      'badge-purple',
  mixed:    'badge-yellow',
  cash_upi: 'badge-yellow',
};
const payLabel = {
  cash:     '💵 Cash',
  card:     '💳 Card',
  upi:      '📱 UPI',
  mixed:    '💵+💳 Cash & Card',
  cash_upi: '💵+📱 Cash & UPI',
};

// ─────────────────────────────────────────────────────────────────────────────
// SearchBar
// FIX: barcode scanners fire chars + Enter before the 300ms debounce fires.
// We cancel the debounce on Enter, then pick from the open dropdown (keyboard
// nav path) OR do a direct barcode lookup (scanner path). One path → one add.
// ─────────────────────────────────────────────────────────────────────────────
function SearchBar({ onAdd }) {
  const [query, setQuery] = useState('');
  const [results, setResults] = useState([]);
  const [searching, setSearching] = useState(false);
  const [selectedIdx, setSelectedIdx] = useState(0);
  const inputRef = useRef();
  const debounceRef = useRef();
  const resultsRef = useRef([]);
  resultsRef.current = results;

  const doSearch = useCallback(async q => {
    if (!q.trim()) { setResults([]); return; }
    setSearching(true);
    try {
      const { data } = await searchProducts(q);
      setResults(data);
      setSelectedIdx(0);
    } catch { setResults([]); }
    finally { setSearching(false); }
  }, []);

  const handleChange = e => {
    const v = e.target.value;
    setQuery(v);
    clearTimeout(debounceRef.current);
    debounceRef.current = setTimeout(() => doSearch(v), 300);
  };

  const selectProduct = useCallback(p => {
    if (p.stock_quantity < 1) { toast.error(`${p.name} is OUT OF STOCK`); return; }
    onAdd(p);
    setQuery('');
    setResults([]);
    clearTimeout(debounceRef.current);
    setTimeout(() => inputRef.current?.focus(), 50);
  }, [onAdd]);

  const handleKeyDown = async e => {
    if (e.key === 'ArrowDown') { e.preventDefault(); setSelectedIdx(i => Math.min(i + 1, resultsRef.current.length - 1)); return; }
    if (e.key === 'ArrowUp')   { e.preventDefault(); setSelectedIdx(i => Math.max(i - 1, 0)); return; }
    if (e.key === 'Escape')    { setResults([]); setQuery(''); clearTimeout(debounceRef.current); return; }

    if (e.key === 'Enter') {
      e.preventDefault();
      clearTimeout(debounceRef.current);
      const current = resultsRef.current;
      if (current.length > 0) {
        selectProduct(current[selectedIdx] || current[0]);
      } else {
        const q = query.trim();
        if (!q) return;
        try {
          const { data } = await getProductByBarcode(q);
          selectProduct(data);
        } catch {
          toast.error('Product not found');
        }
      }
    }
  };

  return (
    <div style={{ position: 'relative' }}>
      <input
        ref={inputRef}
        value={query}
        onChange={handleChange}
        onKeyDown={handleKeyDown}
        placeholder="🔍  Scan barcode or type product name…"
        style={{ fontSize: 16, padding: '12px 16px' }}
        autoFocus
      />
      {searching && (
        <div style={{ position: 'absolute', right: 14, top: 14, color: 'var(--text3)', fontSize: 12 }}>
          searching…
        </div>
      )}
      {results.length > 0 && (
        <div style={{
          position: 'absolute', top: '100%', left: 0, right: 0, zIndex: 200,
          background: 'var(--surface)', border: '1px solid var(--border)',
          borderRadius: 'var(--radius)', marginTop: 4, overflow: 'hidden',
          boxShadow: 'var(--shadow)'
        }}>
          <table>
            <thead>
              <tr><th>Barcode</th><th>Product</th><th>Price</th><th>Stock</th></tr>
            </thead>
            <tbody>
              {results.map((p, i) => (
                <tr key={p.id} onClick={() => selectProduct(p)}
                  style={{ cursor: 'pointer', background: i === selectedIdx ? 'var(--accent-dim)' : undefined }}>
                  <td><span style={{ fontFamily: 'var(--mono)', fontSize: 12 }}>{p.barcode}</span></td>
                  <td style={{ fontWeight: 600, color: 'var(--text)' }}>{p.name}</td>
                  <td style={{ color: 'var(--accent)', fontWeight: 600 }}>{fmt(p.selling_price)}</td>
                  <td>
                    {p.stock_quantity < 1
                      ? <span className="badge badge-red">Out of Stock</span>
                      : <span className="badge badge-green">{p.stock_quantity}</span>}
                  </td>
                </tr>
              ))}
            </tbody>
          </table>
        </div>
      )}
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// BillTable
// ─────────────────────────────────────────────────────────────────────────────
function BillTable({ items, onQtyChange, onRemove }) {
  const total = items.reduce((s, i) => s + i.price * i.qty, 0);

  if (!items.length) return (
    <div className="empty-state" style={{ padding: '40px 0' }}>
      <div className="icon">🛒</div>
      <div>No items added. Scan or search a product above.</div>
    </div>
  );

  return (
    <div>
      <table>
        <thead>
          <tr><th>#</th><th>Product</th><th>Price</th><th>Qty</th><th>Subtotal</th><th></th></tr>
        </thead>
        <tbody>
          {items.map((item, i) => (
            <tr key={item.id}>
              <td style={{ color: 'var(--text3)' }}>{i + 1}</td>
              <td>
                <div style={{ fontWeight: 600, color: 'var(--text)' }}>{item.name}</div>
                <div style={{ fontSize: 11, color: 'var(--text3)', fontFamily: 'var(--mono)' }}>{item.barcode}</div>
              </td>
              <td style={{ color: 'var(--accent)', fontWeight: 600 }}>{fmt(item.price)}</td>
              <td>
                <div style={{ display: 'flex', alignItems: 'center', gap: 6 }}>
                  <button className="btn btn-secondary btn-sm" onClick={() => onQtyChange(item.id, -1)} style={{ padding: '2px 8px' }}>−</button>
                  <span style={{ fontFamily: 'var(--mono)', minWidth: 24, textAlign: 'center' }}>{item.qty}</span>
                  <button className="btn btn-secondary btn-sm" onClick={() => onQtyChange(item.id, 1)} style={{ padding: '2px 8px' }}>+</button>
                </div>
              </td>
              <td style={{ fontWeight: 700, color: 'var(--text)' }}>{fmt(item.price * item.qty)}</td>
              <td>
                <button className="btn btn-danger btn-sm" onClick={() => onRemove(item.id)}>✕</button>
              </td>
            </tr>
          ))}
        </tbody>
      </table>
      <div style={{
        display: 'flex', justifyContent: 'flex-end', padding: '16px 14px',
        borderTop: '2px solid var(--accent)', marginTop: 8
      }}>
        <div>
          <span style={{ color: 'var(--text3)', fontSize: 14, marginRight: 16 }}>TOTAL</span>
          <span style={{ fontSize: 28, fontWeight: 800, fontFamily: 'var(--mono)', color: 'var(--accent)' }}>{fmt(total)}</span>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// PaymentModal
// - Single payment: Cash, Card, UPI buttons
// - Split payment: Cash + Card OR Cash + UPI
// - Auto-fill: typing cash auto-calculates credit and vice versa
// - Live balance indicator shows if amounts match
// ─────────────────────────────────────────────────────────────────────────────
function PaymentModal({ total, onClose, onConfirm }) {
  const [cashAmt, setCashAmt] = useState('');
  const [creditAmt, setCreditAmt] = useState('');
  const [creditType, setCreditType] = useState('card'); // 'card' or 'upi'

  const handleCashChange = e => {
    const c = e.target.value;
    setCashAmt(c);
    const remaining = total - (parseFloat(c) || 0);
    setCreditAmt(remaining > 0 ? remaining.toFixed(2) : '0.00');
  };

  const handleCreditChange = e => {
    const k = e.target.value;
    setCreditAmt(k);
    const remaining = total - (parseFloat(k) || 0);
    setCashAmt(remaining > 0 ? remaining.toFixed(2) : '0.00');
  };

  const cashVal   = parseFloat(cashAmt)   || 0;
  const creditVal = parseFloat(creditAmt) || 0;
  const splitSum  = cashVal + creditVal;
  const splitOk   = Math.abs(splitSum - total) < 0.01;

  const handleMixed = () => {
    if (!splitOk) { toast.error(`Amounts must sum to ${fmt(total)}`); return; }
    // payment_type: 'mixed' = Cash+Card, 'cash_upi' = Cash+UPI
    const payType = creditType === 'upi' ? 'cash_upi' : 'mixed';
    onConfirm(payType, cashVal, creditVal, creditType);
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>💳 Select Payment Method</h2>
        <p style={{ color: 'var(--text3)', marginBottom: 20, fontSize: 14 }}>
          Total: <strong style={{ color: 'var(--accent)', fontSize: 20 }}>{fmt(total)}</strong>
        </p>

        {/* Single payment */}
        <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 12, marginBottom: 24 }}>
          {[
            { label: '💵 Cash', type: 'cash', rgb: '34,197,94',  color: 'var(--green)' },
            { label: '💳 Card', type: 'card', rgb: '59,130,246', color: 'var(--blue)' },
            { label: '📱 UPI',  type: 'upi',  rgb: '168,85,247', color: 'var(--purple)' },
          ].map(p => (
            <button key={p.type}
              onClick={() => onConfirm(p.type, p.type === 'cash' ? total : 0, p.type !== 'cash' ? total : 0, p.type)}
              className="btn" style={{
                background: `rgba(${p.rgb},0.15)`, color: p.color,
                border: `1px solid ${p.color}`, justifyContent: 'center', padding: 16, fontSize: 15
              }}>
              {p.label}
            </button>
          ))}
        </div>

        {/* Split payment */}
        <div style={{ borderTop: '1px solid var(--border)', paddingTop: 20 }}>
          <p style={{ fontSize: 13, fontWeight: 700, marginBottom: 14, color: 'var(--text2)' }}>
            💵 Cash + Credit Split
          </p>

          {/* Credit type toggle */}
          <div className="form-group">
            <label>Credit Type</label>
            <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
              {[
                { v: 'card', label: '💳 Card', color: 'var(--blue)' },
                { v: 'upi',  label: '📱 UPI',  color: 'var(--purple)' },
              ].map(t => (
                <button key={t.v} onClick={() => setCreditType(t.v)} className="btn" style={{
                  flex: 1, justifyContent: 'center', padding: '9px',
                  background: creditType === t.v ? `rgba(255,255,255,0.08)` : 'var(--bg3)',
                  color: t.color,
                  border: `1px solid ${creditType === t.v ? t.color : 'var(--border)'}`,
                  fontWeight: creditType === t.v ? 700 : 400,
                }}>{t.label}</button>
              ))}
            </div>
          </div>

          {/* Amount inputs with auto-fill */}
          <div className="form-row" style={{ marginBottom: 10 }}>
            <div className="form-group" style={{ margin: 0 }}>
              <label>💵 Cash Amount (₹)</label>
              <input
                type="number" value={cashAmt}
                onChange={handleCashChange}
                placeholder="0.00" min="0" max={total}
              />
            </div>
            <div className="form-group" style={{ margin: 0 }}>
              <label>{creditType === 'card' ? '💳 Card' : '📱 UPI'} Amount (₹)</label>
              <input
                type="number" value={creditAmt}
                onChange={handleCreditChange}
                placeholder="0.00" min="0" max={total}
              />
            </div>
          </div>

          {/* Live balance indicator */}
          {(cashAmt !== '' || creditAmt !== '') && (
            <div style={{
              fontSize: 12, marginBottom: 14, padding: '8px 12px',
              borderRadius: 'var(--radius)',
              background: splitOk ? 'var(--green-dim)' : 'var(--red-dim)',
              color: splitOk ? 'var(--green)' : 'var(--red)',
            }}>
              {splitOk
                ? '✓ Amounts match total'
                : `Still remaining: ${fmt(total - splitSum)}`}
            </div>
          )}

          <button
            className="btn btn-primary"
            style={{ width: '100%', justifyContent: 'center' }}
            onClick={handleMixed}
            disabled={!splitOk && (cashAmt !== '' || creditAmt !== '')}
          >
            Confirm {creditType === 'card' ? '💳 Card' : '📱 UPI'} + Cash Split
          </button>
        </div>

        <button className="btn btn-secondary"
          style={{ width: '100%', justifyContent: 'center', marginTop: 12 }}
          onClick={onClose}>
          Cancel
        </button>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// EditPaymentModal
// ─────────────────────────────────────────────────────────────────────────────
function EditPaymentModal({ bill, onClose, onSaved }) {
  const [payType, setPayType] = useState(bill.payment_type);
  const [cashAmt, setCashAmt] = useState(String(bill.cash_amount || ''));
  const [creditAmt, setCreditAmt] = useState(String(bill.card_amount || ''));
  const [creditType, setCreditType] = useState(
    bill.payment_type === 'cash_upi' ? 'upi' : 'card'
  );
  const [loading, setLoading] = useState(false);

  const total = parseFloat(bill.total_amount);

  const handleCashChange = e => {
    const c = e.target.value;
    setCashAmt(c);
    const remaining = total - (parseFloat(c) || 0);
    setCreditAmt(remaining > 0 ? remaining.toFixed(2) : '0.00');
  };

  const handleCreditChange = e => {
    const k = e.target.value;
    setCreditAmt(k);
    const remaining = total - (parseFloat(k) || 0);
    setCashAmt(remaining > 0 ? remaining.toFixed(2) : '0.00');
  };

  const isSplit = payType === 'mixed' || payType === 'cash_upi';
  const cashVal   = parseFloat(cashAmt)   || 0;
  const creditVal = parseFloat(creditAmt) || 0;
  const splitOk   = Math.abs(cashVal + creditVal - total) < 0.01;

  const handleSave = async () => {
    if (isSplit && !splitOk) {
      toast.error(`Amounts must sum to ${fmt(total)}`);
      return;
    }
    setLoading(true);
    try {
      const effectiveType = isSplit
        ? (creditType === 'upi' ? 'cash_upi' : 'mixed')
        : payType;
      const payload = {
        payment_type: effectiveType,
        cash_amount: isSplit ? cashVal : (payType === 'cash' ? total : 0),
        card_amount: isSplit && creditType === 'card' ? creditVal : (payType === 'card' ? total : 0),
      };
      await editBillPayment(bill.id, payload);
      toast.success('Payment mode updated');
      onSaved();
      onClose();
    } catch { toast.error('Failed to update payment'); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>✏️ Edit Payment Mode</h2>

        <div style={{ background: 'var(--bg3)', borderRadius: 'var(--radius)', padding: 14, marginBottom: 20 }}>
          <div style={{ fontSize: 12, color: 'var(--text3)', marginBottom: 2 }}>Bill Number</div>
          <div style={{ fontWeight: 700, fontSize: 18, marginBottom: 4 }}>{bill.bill_number}</div>
          <div style={{ color: 'var(--accent)', fontFamily: 'var(--mono)', fontSize: 20, fontWeight: 800 }}>
            {fmt(bill.total_amount)}
          </div>
          <div style={{ fontSize: 12, color: 'var(--text3)', marginTop: 6 }}>
            Current: <span className={`badge ${payColor[bill.payment_type]}`}>{payLabel[bill.payment_type]}</span>
          </div>
        </div>

        <div className="form-group">
          <label>New Payment Type</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr', gap: 8, marginTop: 4 }}>
            {[
              { v: 'cash',     label: '💵 Cash',         color: 'var(--green)' },
              { v: 'card',     label: '💳 Card',         color: 'var(--blue)' },
              { v: 'upi',      label: '📱 UPI',          color: 'var(--purple)' },
              { v: 'split',    label: '💵 Cash + Credit', color: 'var(--yellow)' },
            ].map(t => (
              <button key={t.v} onClick={() => {
                if (t.v === 'split') {
                  setPayType(creditType === 'upi' ? 'cash_upi' : 'mixed');
                } else {
                  setPayType(t.v);
                }
              }} className="btn" style={{
                justifyContent: 'center', padding: '10px',
                background: (t.v === 'split' ? isSplit : payType === t.v)
                  ? 'rgba(255,255,255,0.08)' : 'var(--bg3)',
                color: t.color,
                border: `1px solid ${(t.v === 'split' ? isSplit : payType === t.v) ? t.color : 'var(--border)'}`,
                fontWeight: (t.v === 'split' ? isSplit : payType === t.v) ? 700 : 400,
              }}>{t.label}</button>
            ))}
          </div>
        </div>

        {isSplit && (
          <>
            <div className="form-group">
              <label>Credit Type</label>
              <div style={{ display: 'flex', gap: 8, marginTop: 4 }}>
                {[
                  { v: 'card', label: '💳 Card', color: 'var(--blue)' },
                  { v: 'upi',  label: '📱 UPI',  color: 'var(--purple)' },
                ].map(t => (
                  <button key={t.v} onClick={() => {
                    setCreditType(t.v);
                    setPayType(t.v === 'upi' ? 'cash_upi' : 'mixed');
                  }} className="btn" style={{
                    flex: 1, justifyContent: 'center', padding: '8px',
                    background: creditType === t.v ? 'rgba(255,255,255,0.08)' : 'var(--bg3)',
                    color: t.color,
                    border: `1px solid ${creditType === t.v ? t.color : 'var(--border)'}`,
                    fontWeight: creditType === t.v ? 700 : 400,
                  }}>{t.label}</button>
                ))}
              </div>
            </div>

            <div className="form-row" style={{ marginBottom: 10 }}>
              <div className="form-group" style={{ margin: 0 }}>
                <label>💵 Cash Amount (₹)</label>
                <input type="number" value={cashAmt} onChange={handleCashChange} placeholder="0.00" />
              </div>
              <div className="form-group" style={{ margin: 0 }}>
                <label>{creditType === 'card' ? '💳 Card' : '📱 UPI'} Amount (₹)</label>
                <input type="number" value={creditAmt} onChange={handleCreditChange} placeholder="0.00" />
              </div>
            </div>

            {(cashAmt !== '' || creditAmt !== '') && (
              <div style={{
                fontSize: 12, marginBottom: 12, padding: '8px 12px',
                borderRadius: 'var(--radius)',
                background: splitOk ? 'var(--green-dim)' : 'var(--red-dim)',
                color: splitOk ? 'var(--green)' : 'var(--red)',
              }}>
                {splitOk ? '✓ Amounts match total' : `Still remaining: ${fmt(total - cashVal - creditVal)}`}
              </div>
            )}
          </>
        )}

        <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
          <button className="btn btn-primary" style={{ flex: 1, justifyContent: 'center' }}
            onClick={handleSave} disabled={loading}>
            {loading ? 'Saving…' : '✓ Save Changes'}
          </button>
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// ViewBillsModal — search by bill number, view, edit payment, delete
// ─────────────────────────────────────────────────────────────────────────────
function ViewBillsModal({ onClose }) {
  const [bills, setBills] = useState([]);
  const [loading, setLoading] = useState(true);
  const [search, setSearch] = useState('');
  const [detailBill, setDetailBill] = useState(null);
  const [editingBill, setEditingBill] = useState(null);
  const [deleting, setDeleting] = useState(null);

  const fetchBills = async () => {
    setLoading(true);
    try {
      const { data } = await getBills();
      setBills(data);
    } catch { toast.error('Failed to load bills'); }
    finally { setLoading(false); }
  };

  useEffect(() => { fetchBills(); }, []);

  const openBill = async b => {
    try {
      const { data } = await getBill(b.id);
      setDetailBill(data);
    } catch { toast.error('Failed to load bill details'); }
  };

  const handleDelete = async b => {
    if (!window.confirm(`Delete bill ${b.bill_number}?\n\nStock for all items will be restored.`)) return;
    setDeleting(b.id);
    try {
      await deleteBill(b.id);
      toast.success(`Bill ${b.bill_number} deleted — stock restored`);
      fetchBills();
    } catch { toast.error('Failed to delete bill'); }
    finally { setDeleting(null); }
  };

  if (detailBill) return <PrintBill bill={detailBill} onClose={() => setDetailBill(null)} />;
  if (editingBill) return (
    <EditPaymentModal
      bill={editingBill}
      onClose={() => setEditingBill(null)}
      onSaved={fetchBills}
    />
  );

  const filtered = bills.filter(b =>
    b.bill_number.toLowerCase().includes(search.toLowerCase())
  );

  return (
    <div className="modal-overlay">
      <div className="modal" style={{ maxWidth: 820, maxHeight: '85vh', overflow: 'hidden', display: 'flex', flexDirection: 'column' }}>
        <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', marginBottom: 16 }}>
          <h2 style={{ margin: 0 }}>📋 Bills</h2>
          <button className="btn btn-secondary btn-sm" onClick={onClose}>✕ Close</button>
        </div>

        {/* Bill number search */}
        <input
          value={search}
          onChange={e => setSearch(e.target.value)}
          placeholder="🔍  Search by bill number (e.g. BS000001)…"
          style={{ marginBottom: 16 }}
          autoFocus
        />

        {loading ? <div className="spinner" /> : (
          <div style={{ overflowY: 'auto' }}>
            <table>
              <thead>
                <tr>
                  <th>Bill No</th>
                  <th>Date & Time</th>
                  <th>Payment Mode</th>
                  <th>Total</th>
                  <th style={{ textAlign: 'right' }}>Actions</th>
                </tr>
              </thead>
              <tbody>
                {filtered.map(b => (
                  <tr key={b.id}>
                    <td>
                      <span className="badge badge-orange" style={{ fontFamily: 'var(--mono)' }}>
                        {b.bill_number}
                      </span>
                    </td>
                    <td style={{ fontSize: 12, color: 'var(--text3)' }}>
                      {new Date(b.created_at).toLocaleString()}
                    </td>
                    <td>
                      <span className={`badge ${payColor[b.payment_type] || 'badge-orange'}`}>
                        {payLabel[b.payment_type] || b.payment_type}
                      </span>
                      {(b.payment_type === 'mixed' || b.payment_type === 'cash_upi') && (
                        <div style={{ fontSize: 11, color: 'var(--text3)', marginTop: 3 }}>
                          Cash: {fmt(b.cash_amount)} | {b.payment_type === 'cash_upi' ? 'UPI' : 'Card'}: {fmt(b.card_amount)}
                        </div>
                      )}
                    </td>
                    <td style={{ fontWeight: 700, color: 'var(--accent)', fontFamily: 'var(--mono)' }}>
                      {fmt(b.total_amount)}
                    </td>
                    <td>
                      <div style={{ display: 'flex', gap: 6, justifyContent: 'flex-end' }}>
                        <button className="btn btn-secondary btn-sm" onClick={() => openBill(b)}>
                          🖨️ View
                        </button>
                        <button className="btn btn-secondary btn-sm" onClick={() => setEditingBill(b)}
                          style={{ color: 'var(--blue)', borderColor: 'var(--blue)' }}>
                          ✏️ Edit
                        </button>
                        <button className="btn btn-danger btn-sm" onClick={() => handleDelete(b)}
                          disabled={deleting === b.id} title="Delete bill and restore stock">
                          {deleting === b.id ? '…' : '🗑️'}
                        </button>
                      </div>
                    </td>
                  </tr>
                ))}
              </tbody>
            </table>
            {filtered.length === 0 && (
              <div className="empty-state">
                <div className="icon">📄</div>
                {search ? `No bills matching "${search}"` : 'No bills yet'}
              </div>
            )}
          </div>
        )}
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// ReturnModal
// ─────────────────────────────────────────────────────────────────────────────
function ReturnModal({ onClose }) {
  const [query, setQuery] = useState('');
  const [product, setProduct] = useState(null);
  const [returnType, setReturnType] = useState('');
  const [loading, setLoading] = useState(false);

  const handleScan = async e => {
    if (e.key !== 'Enter') return;
    if (!query.trim()) return;
    try {
      const { data } = await getProductByBarcode(query.trim());
      setProduct(data);
      setReturnType('');
    } catch { toast.error('Product not found'); }
  };

  const handleReturn = async () => {
    if (!product || !returnType) { toast.error('Select return type'); return; }
    setLoading(true);
    try {
      const { createReturn } = await import('../services/api');
      await createReturn({ product: product.id, return_type: returnType, quantity: 1 });
      toast.success(`Return processed: ${returnType.replace('_', ' ')}`);
      onClose();
    } catch { toast.error('Failed to process return'); }
    finally { setLoading(false); }
  };

  return (
    <div className="modal-overlay">
      <div className="modal">
        <h2>↩️ Process Return</h2>
        <div className="form-group">
          <label>Scan / Enter Barcode</label>
          <input autoFocus value={query} onChange={e => setQuery(e.target.value)}
            onKeyDown={handleScan} placeholder="Scan barcode and press Enter…" />
        </div>
        {product && (
          <div style={{ background: 'var(--bg3)', borderRadius: 'var(--radius)', padding: 16, marginBottom: 16 }}>
            <div style={{ fontWeight: 700, fontSize: 16, marginBottom: 4 }}>{product.name}</div>
            <div style={{ display: 'flex', gap: 16, fontSize: 13, color: 'var(--text3)' }}>
              <span>Barcode: <b style={{ color: 'var(--text2)', fontFamily: 'var(--mono)' }}>{product.barcode}</b></span>
              <span>MRP: <b style={{ color: 'var(--accent)' }}>{fmt(product.selling_price)}</b></span>
              <span>Stock: <b style={{ color: 'var(--green)' }}>{product.stock_quantity}</b></span>
            </div>
          </div>
        )}
        <div className="form-group">
          <label>Return Type</label>
          <div style={{ display: 'grid', gridTemplateColumns: '1fr 1fr 1fr', gap: 8, marginTop: 4 }}>
            {[
              { v: 'customer_return', label: '👤 Customer Return', color: 'var(--green)' },
              { v: 'damaged',         label: '⚠️ Damaged',         color: 'var(--yellow)' },
              { v: 'expired',         label: '🗑️ Expired',         color: 'var(--red)' },
            ].map(t => (
              <button key={t.v} onClick={() => setReturnType(t.v)} className="btn" style={{
                justifyContent: 'center', fontSize: 12, padding: '10px 6px',
                background: returnType === t.v ? 'rgba(255,255,255,0.1)' : 'var(--bg3)',
                color: t.color, border: `1px solid ${returnType === t.v ? t.color : 'var(--border)'}`,
              }}>{t.label}</button>
            ))}
          </div>
        </div>
        <div style={{ display: 'flex', gap: 10, marginTop: 8 }}>
          <button className="btn btn-primary" onClick={handleReturn}
            disabled={!product || !returnType || loading} style={{ flex: 1, justifyContent: 'center' }}>
            {loading ? 'Processing…' : 'Process Return'}
          </button>
          <button className="btn btn-secondary" onClick={onClose}>Cancel</button>
        </div>
      </div>
    </div>
  );
}

// ─────────────────────────────────────────────────────────────────────────────
// Main Sale Page
// ─────────────────────────────────────────────────────────────────────────────
export default function Sale() {
  const [items, setItems] = useState([]);
  const [showPayment, setShowPayment] = useState(false);
  const [showBills, setShowBills] = useState(false);
  const [showReturn, setShowReturn] = useState(false);
  const [printBill, setPrintBill] = useState(null);

  const addItem = p => {
    setItems(prev => {
      const existing = prev.find(i => i.id === p.id);
      if (existing) {
        if (existing.qty >= p.stock_quantity) { toast.error('Not enough stock'); return prev; }
        return prev.map(i => i.id === p.id ? { ...i, qty: i.qty + 1 } : i);
      }
      return [...prev, {
        id: p.id, name: p.name, barcode: p.barcode,
        price: parseFloat(p.selling_price), qty: 1, stock: p.stock_quantity
      }];
    });
  };

  const changeQty = (id, delta) => {
    setItems(prev => prev.map(i => {
      if (i.id !== id) return i;
      const newQty = i.qty + delta;
      if (newQty < 1) return i;
      if (newQty > i.stock) { toast.error('Not enough stock'); return i; }
      return { ...i, qty: newQty };
    }));
  };

  const removeItem = id => setItems(prev => prev.filter(i => i.id !== id));
  const total = items.reduce((s, i) => s + i.price * i.qty, 0);

  const confirmPayment = async (payType, cashAmt, cardAmt) => {
    setShowPayment(false);
    try {
      const payload = {
        total_amount: total,
        payment_type: payType,
        cash_amount: cashAmt || (payType === 'cash' ? total : 0),
        card_amount: cardAmt || (payType === 'card' ? total : 0),
        items: items.map(i => ({ product: i.id, quantity: i.qty, price: i.price })),
      };
      const { data } = await createBill(payload);
      toast.success(`Bill ${data.bill_number} saved!`);
      setItems([]);
      setPrintBill(data);
    } catch (err) {
      toast.error(err.response?.data?.detail || 'Failed to save bill');
    }
  };

  if (printBill) return <PrintBill bill={printBill} onClose={() => setPrintBill(null)} />;

  return (
    <div>
      <div className="page-header">
        <h1>🛒 Sale</h1>
        <div style={{ display: 'flex', gap: 10 }}>
          <button className="btn btn-secondary" onClick={() => setShowReturn(true)}>↩️ Return</button>
          <button className="btn btn-secondary" onClick={() => setShowBills(true)}>📋 View Bills</button>
          {items.length > 0 && (
            <button className="btn btn-primary" onClick={() => setShowPayment(true)}>
              💳 Pay {fmt(total)}
            </button>
          )}
        </div>
      </div>

      <div className="card" style={{ marginBottom: 20 }}>
        <SearchBar onAdd={addItem} />
      </div>

      <div className="card">
        <BillTable items={items} onQtyChange={changeQty} onRemove={removeItem} />
        {items.length > 0 && (
          <div style={{ display: 'flex', gap: 12, marginTop: 16, borderTop: '1px solid var(--border)', paddingTop: 16 }}>
            {['cash', 'card', 'upi', 'mixed'].map((type, i) => {
              const labels = { cash: '💵 Cash', card: '💳 Card', upi: '📱 UPI', mixed: '💵+💳 Split' };
              const colors = ['var(--green)', 'var(--blue)', 'var(--purple)', 'var(--yellow)'];
              return (
                <button key={type} onClick={() => {
                  if (type === 'mixed') { setShowPayment(true); return; }
                  confirmPayment(type, type === 'cash' ? total : 0, type === 'card' ? total : 0);
                }} className="btn" style={{
                  flex: 1, justifyContent: 'center', padding: '12px',
                  background: `rgba(${['34,197,94','59,130,246','168,85,247','234,179,8'][i]},0.15)`,
                  color: colors[i], border: `1px solid ${colors[i]}`, fontSize: 14, fontWeight: 700
                }}>
                  {labels[type]}
                </button>
              );
            })}
          </div>
        )}
      </div>

      {showPayment && <PaymentModal total={total} onClose={() => setShowPayment(false)} onConfirm={confirmPayment} />}
      {showBills   && <ViewBillsModal onClose={() => setShowBills(false)} />}
      {showReturn  && <ReturnModal onClose={() => setShowReturn(false)} />}
    </div>
  );
}
